import{_ as i,o as t,c as o,ag as a}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"Spec: Terminal User Interface (TUI)","description":"","frontmatter":{},"headers":[],"relativePath":"spec/07_tui.md","filePath":"spec/07_tui.md","lastUpdated":1775245708000}'),l={name:"spec/07_tui.md"};function n(s,e,r,c,d,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="spec-terminal-user-interface-tui" tabindex="-1">Spec: Terminal User Interface (TUI) <a class="header-anchor" href="#spec-terminal-user-interface-tui" aria-label="Permalink to &quot;Spec: Terminal User Interface (TUI)&quot;">​</a></h1><p><strong>Status</strong>: ✅ Done (core); 🔶 Missing (vim mode, output styles, history search) <strong>Rust crate</strong>: <code>piko-tui</code><strong>TS source</strong>: <code>ink/</code>, <code>components/</code>, <code>hooks/</code></p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The TUI is built with <code>ratatui</code> + <code>crossterm</code>. It provides an interactive chat interface with a chat pane, input bar, status bar, permission dialogs, and question dialogs.</p><hr><h2 id="what-s-implemented" tabindex="-1">What&#39;s Implemented <a class="header-anchor" href="#what-s-implemented" aria-label="Permalink to &quot;What&#39;s Implemented&quot;">​</a></h2><h3 id="app-state-machine-✅" tabindex="-1">App State Machine ✅ <a class="header-anchor" href="#app-state-machine-✅" aria-label="Permalink to &quot;App State Machine ✅&quot;">​</a></h3><ul><li>[x] <code>AppState</code> enum: <code>Running</code>, <code>WaitingForAgent</code>, <code>AskingPermission</code>, <code>AskingQuestion</code>, <code>Exiting</code></li><li>[x] Event-driven loop: keyboard events + agent events processed in single <code>select!</code> loop</li><li>[x] Graceful exit on <code>Ctrl+C</code> / <code>Ctrl+D</code> (sends cancellation to agent, then exits)</li></ul><h3 id="chat-pane-✅" tabindex="-1">Chat Pane ✅ <a class="header-anchor" href="#chat-pane-✅" aria-label="Permalink to &quot;Chat Pane ✅&quot;">​</a></h3><ul><li>[x] Scrollable message history</li><li>[x] User messages, assistant text, tool start/result display</li><li>[x] Syntax-highlighted code blocks (via <code>syntect</code>, 190+ languages, TextMate grammars)</li><li>[x] Markdown-aware rendering (bold, italic, inline code, headers, lists)</li><li>[x] Scroll with <code>↑/↓</code> or <code>PgUp/PgDn</code></li><li>[x] Auto-scroll to bottom on new messages</li></ul><h3 id="input-bar-✅" tabindex="-1">Input Bar ✅ <a class="header-anchor" href="#input-bar-✅" aria-label="Permalink to &quot;Input Bar ✅&quot;">​</a></h3><ul><li>[x] Multi-line input (Shift+Enter for newline)</li><li>[x] Enter to submit</li><li>[x] Basic cursor movement (left/right/home/end)</li><li>[x] Backspace/delete</li><li>[x] Paste support (clipboard paste inserts at cursor)</li></ul><h3 id="status-bar-✅" tabindex="-1">Status Bar ✅ <a class="header-anchor" href="#status-bar-✅" aria-label="Permalink to &quot;Status Bar ✅&quot;">​</a></h3><ul><li>[x] Model name display</li><li>[x] Current working directory display</li><li>[x] Token usage: cumulative input / output / cache_creation / cache_read</li><li>[x] Active theme name</li><li>[x] Rate limit warning when rate limit is hit</li></ul><h3 id="permission-dialog-✅" tabindex="-1">Permission Dialog ✅ <a class="header-anchor" href="#permission-dialog-✅" aria-label="Permalink to &quot;Permission Dialog ✅&quot;">​</a></h3><ul><li>[x] Inline dialog appears when <code>PermissionAsk</code> event received</li><li>[x] Shows tool name and relevant input preview</li><li>[x] Keybindings: <code>y</code>/<code>n</code>/<code>a</code>/<code>d</code></li><li>[x] Blocks agent until user responds</li><li>[x] Returns decision via channel back to permission checker</li></ul><h3 id="question-dialog-✅" tabindex="-1">Question Dialog ✅ <a class="header-anchor" href="#question-dialog-✅" aria-label="Permalink to &quot;Question Dialog ✅&quot;">​</a></h3><ul><li>[x] Inline numbered option list for <code>AskUserQuestion</code> tool</li><li>[x] Type number to select, or free-text</li><li>[x] Returns answer via channel back to tool</li></ul><h3 id="themes-✅" tabindex="-1">Themes ✅ <a class="header-anchor" href="#themes-✅" aria-label="Permalink to &quot;Themes ✅&quot;">​</a></h3><ul><li>[x] 6 built-in themes: <code>dark</code>, <code>light</code>, <code>dark-daltonized</code>, <code>light-daltonized</code>, <code>dark-ansi</code>, <code>light-ansi</code></li><li>[x] <code>/theme [name]</code> command to switch mid-session</li><li>[x] Active theme shown in status bar</li><li>[x] Full-frame background fill (no terminal default bleed)</li><li>[x] Theme persisted to <code>~/.config/pikoclaw/config.toml</code></li></ul><h3 id="first-run-onboarding-✅" tabindex="-1">First-Run Onboarding ✅ <a class="header-anchor" href="#first-run-onboarding-✅" aria-label="Permalink to &quot;First-Run Onboarding ✅&quot;">​</a></h3><ul><li>[x] Full-screen theme picker on first launch</li><li>[x] Live preview of theme with color swatches</li><li>[x] Navigate with arrow keys, confirm with Enter</li><li>[x] Sets <code>onboarding_done: true</code> in config after completion</li></ul><h3 id="welcome-header-✅" tabindex="-1">Welcome Header ✅ <a class="header-anchor" href="#welcome-header-✅" aria-label="Permalink to &quot;Welcome Header ✅&quot;">​</a></h3><ul><li>[x] Versioned border</li><li>[x] Pixel-art Clawd logo</li><li>[x] Model name and cwd info</li><li>[x] Tips panel</li><li>[x] Recent activity panel (last N sessions from index)</li></ul><h3 id="syntax-highlighting-✅" tabindex="-1">Syntax Highlighting ✅ <a class="header-anchor" href="#syntax-highlighting-✅" aria-label="Permalink to &quot;Syntax Highlighting ✅&quot;">​</a></h3><ul><li>[x] <code>syntect</code> with embedded TextMate grammars</li><li>[x] Detects language from fenced code block (<code>rust, </code>python, etc.)</li><li>[x] Falls back to plain text if language not detected</li><li>[x] Theme-aware colors</li></ul><hr><h2 id="gaps-todos" tabindex="-1">Gaps / Todos <a class="header-anchor" href="#gaps-todos" aria-label="Permalink to &quot;Gaps / Todos&quot;">​</a></h2><ul><li><p>[ ] <strong>Vim keybinding mode</strong> — <code>/vim</code> command and <code>vim_mode: true</code> config. Full modal editing in input bar. See <a href="./14_vim_keybindings.html">14_vim_keybindings.md</a></p></li><li><p>[ ] <strong>Input history navigation</strong> — <code>↑/↓</code> in empty input to cycle previous prompts (like shell history).</p><ul><li>Implementation: maintain <code>Vec&lt;String&gt;</code> of past inputs, navigate with arrows when cursor at top/bottom.</li></ul></li><li><p>[ ] <strong>History search</strong> — Ctrl+R to search previous messages/inputs.</p></li><li><p>[ ] <strong>Image rendering</strong> — Display images inline in TUI using sixel/kitty graphics protocol or reference paths. See <a href="./15_image_input.html">15_image_input.md</a></p></li><li><p>[ ] <strong>Configurable output styles</strong> — <code>--output-style</code> flag with styles like <code>minimal</code>, <code>verbose</code>, <code>json</code>. See <a href="./26_output_styles.html">26_output_styles.md</a></p></li><li><p>[ ] <strong><code>/compact</code> visual feedback</strong> — show summary text in TUI after compaction, not just a silent clear.</p></li><li><p>[ ] <strong>Todo list sidebar</strong> — when TodoWrite tool is used, show task checklist in a sidebar or inline panel.</p></li><li><p>[ ] <strong>Agent progress indicator</strong> — show spinner/ellipsis while agent is thinking between tool calls.</p></li><li><p>[ ] <strong>Tool result collapsing</strong> — long tool outputs (e.g. bash stdout) should be collapsible/expandable in TUI.</p></li><li><p>[ ] <strong>Search in output</strong> — Ctrl+F to search through displayed messages.</p></li><li><p>[ ] <strong>Copy to clipboard</strong> — select text in output, copy with Ctrl+C (without interrupting session).</p></li><li><p>[ ] <strong>Resize handling</strong> — currently TUI may not reflow properly on terminal resize. Needs <code>crossterm::event::Event::Resize</code> handling.</p></li></ul>',30)])])}const m=i(l,[["render",n]]);export{p as __pageData,m as default};
